// Generate release notes with commit data
const tagData = $input.item.json;
const tagName = tagData.tagName;
const version = tagData.version;
const major = parseInt(tagData.major) || 0;
const minor = parseInt(tagData.minor) || 0;
const patch = parseInt(tagData.patch) || 0;
const preRelease = tagData.preRelease;
const repository = tagData.repositoryFullName || tagData.repository;
const commitSha = tagData.commitSha;
const baseUrl = tagData.baseUrl;
const defaultBranch = tagData.defaultBranch || 'main';

// Try to get commit data from previous node (HTTP Request)
let commits = [];
let commitCount = 0;
let commitData = null;

try {
  // Check if we have commit data from HTTP Request node
  const httpNode = $('Fetch Commits from Branch');
  if (httpNode && httpNode.first()) {
    commitData = httpNode.first().json;

    // Check for error responses
    if (commitData.error || commitData.message) {
      console.log('API returned error:', commitData.error || commitData.message);
      // Continue without commit data
    }
    // GitHub format
    else if (commitData.commits && Array.isArray(commitData.commits)) {
      commits = commitData.commits.map(c => ({
        sha: c.sha?.substring(0, 7) || '',
        message: c.commit?.message || c.message || '',
        author: c.commit?.author?.name || c.author?.login || c.author?.name || 'unknown',
        date: c.commit?.author?.date || c.date || ''
      }));
      commitCount = commitData.commits.length;
    }
    // GitLab format (cloud & self-hosted)
    else if (commitData.commits && Array.isArray(commitData.commits)) {
      commits = commitData.commits.map(c => ({
        sha: c.id?.substring(0, 7) || c.short_id?.substring(0, 7) || '',
        message: c.message || c.title || '',
        author: c.author_name || c.author?.name || c.committer_name || 'unknown',
        date: c.created_at || c.committed_date || c.date || ''
      }));
      commitCount = commitData.commits.length;
    }
    // GitLab compare API returns commits array directly
    else if (Array.isArray(commitData)) {
      commits = commitData.map(c => ({
        sha: c.id?.substring(0, 7) || c.short_id?.substring(0, 7) || '',
        message: c.message || c.title || '',
        author: c.author_name || c.author?.name || 'unknown',
        date: c.created_at || c.committed_date || ''
      }));
      commitCount = commitData.length;
    }
  }
} catch (e) {
  // If HTTP request failed or not available, continue without commit data
  console.log('No commit data available, continuing without it:', e.message);
}

// Determine release type
let releaseType = '';
let releaseEmoji = '';
let notes = '';

if (preRelease) {
  releaseType = `Pre-release (${preRelease})`;
  releaseEmoji = '🚧';
  notes = `\n${releaseEmoji} **Pre-release Build**\n\nThis is a ${preRelease} release for testing purposes.\n\n`;
} else if (major > 0 && minor === 0 && patch === 0) {
  releaseType = 'Major Release';
  releaseEmoji = '🎉';
  notes = `\n${releaseEmoji} **Major Release**\n\nThis release includes breaking changes and significant new features.\n\n`;
} else if (patch === 0) {
  releaseType = 'Minor Release';
  releaseEmoji = '✨';
  notes = `\n${releaseEmoji} **Minor Release**\n\nThis release includes new features and improvements.\n\n`;
} else {
  releaseType = 'Patch Release';
  releaseEmoji = '🐛';
  notes = `\n${releaseEmoji} **Patch Release**\n\nThis release includes bug fixes and minor improvements.\n\n`;
}

// Add commit information if available
if (commits.length > 0) {
  notes += `**Changes in this release:**\n\n`;
  notes += `Total commits: ${commitCount}\n\n`;

  // Add commit list (limit to 20 most recent)
  const recentCommits = commits.slice(0, 20);
  recentCommits.forEach(commit => {
    const firstLine = commit.message.split('\n')[0];
    notes += `- ${commit.sha}: ${firstLine} (${commit.author})\n`;
  });

  if (commits.length > 20) {
    notes += `\n... and ${commits.length - 20} more commits.\n`;
  }

  notes += `\n**View all changes:** ${baseUrl}/compare/${tagName}...${defaultBranch}\n\n`;
} else {
  notes += `**View changes:** ${baseUrl}/compare/${tagName}...${defaultBranch} or ${baseUrl}/-/tags/${tagName}\n\n`;
}

notes += `**Release Information:**\n`;
notes += `- Version: ${version}\n`;
notes += `- Repository: ${repository}\n`;
notes += `- Release Type: ${releaseType}\n`;
notes += `- Tagged by: ${tagData.tagger}\n`;
if (commitSha) {
  notes += `- Commit: ${commitSha.substring(0, 7)}\n`;
}
notes += `\n**Action Items:**\n`;
notes += `- [ ] Review release notes\n`;
notes += `- [ ] Perform QA testing\n`;
notes += `- [ ] Update deployment documentation\n`;
notes += `- [ ] Notify stakeholders\n`;

return {
  json: {
    ...tagData,
    releaseType: releaseType,
    releaseEmoji: releaseEmoji,
    releaseNotes: notes,
    commitCount: commitCount,
    commits: commits
  }
};
